import{_ as e,o as t,c as r,a2 as i}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"搜索引擎作为派生系统：权威边界、可靠性与容量","description":"","frontmatter":{"stage":"intermediate","direction":"backend-data","topic":"search-derived-system"},"headers":[],"relativePath":"05-backend-data/notes/cache-messaging-storage/15-search-derived-system.md","filePath":"05-backend-data/notes/cache-messaging-storage/15-search-derived-system.md","lastUpdated":1784382745000}'),l={name:"05-backend-data/notes/cache-messaging-storage/15-search-derived-system.md"};function s(h,a,d,o,n,p){return t(),r("div",null,[...a[0]||(a[0]=[i(`<h1 id="搜索引擎作为派生系统-权威边界、可靠性与容量" tabindex="-1">搜索引擎作为派生系统：权威边界、可靠性与容量 <a class="header-anchor" href="#搜索引擎作为派生系统-权威边界、可靠性与容量" aria-label="Permalink to &quot;搜索引擎作为派生系统：权威边界、可靠性与容量&quot;">​</a></h1><p>搜索引擎可存储可查询文档，但不应在产品架构中自动成为订单、余额、授权和用户资料的唯一事实源。派生系统可以丢弃重建，事实系统负责约束、事务、审计和恢复。</p><h2 id="_1-能力边界与机制图" tabindex="-1">1. 能力边界与机制图 <a class="header-anchor" href="#_1-能力边界与机制图" aria-label="Permalink to &quot;1. 能力边界与机制图&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;事实输入&quot;] --&gt; B[&quot;索引/处理机制&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[&quot;查询或派生输出&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[&quot;验证与观测&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[&quot;失败恢复/重建&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>图中的索引只保存事实系统的可重建投影。订单写入、余额计算和最终授权始终回到权威数据库；搜索健康度只决定检索能力是完整、部分还是降级，不能改变交易裁决。</p><h2 id="_2-事实来源" tabindex="-1">2. 事实来源 <a class="header-anchor" href="#_2-事实来源" aria-label="Permalink to &quot;2. 事实来源&quot;">​</a></h2><p>机制：拥有业务不变量和写入裁决。</p><p>实际使用：订单、账户、权限由数据库提交。</p><p>主要失败：让搜索脚本直接扣库存。</p><p>验证方法：故障关闭搜索后核心写仍正确。</p><p>取舍：权威系统延迟高但语义完整。</p><p>生产实现 事实来源 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_3-派生投影" tabindex="-1">3. 派生投影 <a class="header-anchor" href="#_3-派生投影" aria-label="Permalink to &quot;3. 派生投影&quot;">​</a></h2><p>机制：为查询形态复制/反规范化事实。</p><p>实际使用：全文、facet、读模型。</p><p>主要失败：没有重建水位和版本。</p><p>验证方法：删除索引后从事实恢复。</p><p>取舍：查询快但最终一致。</p><p>生产实现 派生投影 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_4-near-real-time" tabindex="-1">4. Near real time <a class="header-anchor" href="#_4-near-real-time" aria-label="Permalink to &quot;4. Near real time&quot;">​</a></h2><p>机制：refresh后新段可搜索，不等同写入提交。</p><p>实际使用：定义search freshness SLO。</p><p>主要失败：写成功立即搜索却无read-your-writes方案。</p><p>验证方法：测commit到visible延迟。</p><p>取舍：短refresh耗资源。</p><p>生产实现 Near real time 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_5-partial-results" tabindex="-1">5. Partial results <a class="header-anchor" href="#_5-partial-results" aria-label="Permalink to &quot;5. Partial results&quot;">​</a></h2><p>机制：分片失败时产品可能返回部分结果。</p><p>实际使用：非关键发现类页面可显式降级。</p><p>主要失败：订单后台把partial当完整清单。</p><p>验证方法：关闭/检测partial并显示状态。</p><p>取舍：可用性与完整性取舍。</p><p>生产实现 Partial results 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_6-quorum与副本" tabindex="-1">6. Quorum与副本 <a class="header-anchor" href="#_6-quorum与副本" aria-label="Permalink to &quot;6. Quorum与副本&quot;">​</a></h2><p>机制：主分片/副本提供搜索和故障恢复。</p><p>实际使用：容量与可用性设计。</p><p>主要失败：副本当独立备份。</p><p>验证方法：故障演练和snapshot restore。</p><p>取舍：更多副本增加写/存储。</p><p>生产实现 Quorum与副本 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_7-snapshot" tabindex="-1">7. Snapshot <a class="header-anchor" href="#_7-snapshot" aria-label="Permalink to &quot;7. Snapshot&quot;">​</a></h2><p>机制：保存索引恢复点到repository。</p><p>实际使用：灾备与快速恢复。</p><p>主要失败：只做snapshot不测restore。</p><p>验证方法：隔离集群恢复验证。</p><p>取舍：不能替代事实重建和跨系统对账。</p><p>生产实现 Snapshot 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_8-权限过滤" tabindex="-1">8. 权限过滤 <a class="header-anchor" href="#_8-权限过滤" aria-label="Permalink to &quot;8. 权限过滤&quot;">​</a></h2><p>机制：tenant/ACL必须进入搜索查询。</p><p>实际使用：防hits、total、aggregation泄露。</p><p>主要失败：先搜索后应用过滤。</p><p>验证方法：越权矩阵与聚合测试。</p><p>取舍：细粒度ACL增加索引/查询成本。</p><p>生产实现 权限过滤 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_9-容量分片" tabindex="-1">9. 容量分片 <a class="header-anchor" href="#_9-容量分片" aria-label="Permalink to &quot;9. 容量分片&quot;">​</a></h2><p>机制：shard是Lucene索引和并行/恢复单位。</p><p>实际使用：按数据量、QPS、节点规划。</p><p>主要失败：大量小shard耗heap，超大shard恢复慢。</p><p>验证方法：测shard size、segment、recovery。</p><p>取舍：需要基于实际压测。</p><p>生产实现 容量分片 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_10-写入背压" tabindex="-1">10. 写入背压 <a class="header-anchor" href="#_10-写入背压" aria-label="Permalink to &quot;10. 写入背压&quot;">​</a></h2><p>机制：bulk queue/rejection保护节点。</p><p>实际使用：consumer减速与retry。</p><p>主要失败：无限重试形成风暴。</p><p>验证方法：监控429和ingest lag。</p><p>取舍：吞吐与freshness取舍。</p><p>生产实现 写入背压 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_11-生命周期" tabindex="-1">11. 生命周期 <a class="header-anchor" href="#_11-生命周期" aria-label="Permalink to &quot;11. 生命周期&quot;">​</a></h2><p>机制：rollover、tier、delete管理时序索引。</p><p>实际使用：日志/事件保留。</p><p>主要失败：把产品主数据按日志策略删。</p><p>验证方法：演练policy和snapshot依赖。</p><p>取舍：自动化需权限和回滚。</p><p>生产实现 生命周期 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_12-方案比较" tabindex="-1">12. 方案比较 <a class="header-anchor" href="#_12-方案比较" aria-label="Permalink to &quot;12. 方案比较&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方案</th><th>主要收益</th><th>关键边界</th></tr></thead><tbody><tr><td>PostgreSQL</td><td>事务约束事实</td><td>全文/大聚合有限</td></tr><tr><td>OpenSearch/Elasticsearch</td><td>全文与聚合</td><td>最终一致/运维</td></tr><tr><td>对象存储快照</td><td>低成本恢复</td><td>不能在线查询</td></tr><tr><td>缓存</td><td>低延迟派生</td><td>易失/查询能力有限</td></tr><tr><td>数据仓库</td><td>分析事实</td><td>非事务在线读</td></tr></tbody></table><h2 id="_13-完整案例-电商搜索降级" tabindex="-1">13. 完整案例：电商搜索降级 <a class="header-anchor" href="#_13-完整案例-电商搜索降级" aria-label="Permalink to &quot;13. 完整案例：电商搜索降级&quot;">​</a></h2><h3 id="输入与约束" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>搜索集群全红20分钟；结算和订单必须可用；发现页可降级。</p><h3 id="处理步骤" tabindex="-1">处理步骤 <a class="header-anchor" href="#处理步骤" aria-label="Permalink to &quot;处理步骤&quot;">​</a></h3><ol><li>API熔断搜索并停止无界重试。</li><li>首页返回缓存分类/热门静态结果并标记搜索不可用。</li><li>结算按商品ID从事实服务读取价格库存。</li><li>索引consumer暂停/积压，不丢offset。</li><li>恢复后渐进追赶并对账版本。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>核心交易正确，搜索能力显式降级。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>关闭搜索故障演练中订单写成功；数据库不被模糊全文替代查询压垮。</p><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>降级为数据库LIKE &#39;%q%&#39;全表扫描会转移事故；只提供受限精确查/静态结果。</p><h3 id="完成判断" tabindex="-1">完成判断 <a class="header-anchor" href="#完成判断" aria-label="Permalink to &quot;完成判断&quot;">​</a></h3><p>电商降级演练必须证明搜索全停时订单写入仍满足数据库约束，备用精确查询受索引与速率限制，恢复后按事实水位补齐投影；禁止以无界 <code>LIKE &#39;%q%&#39;</code> 把故障转移到主库。</p><h2 id="_14-完整案例-多租户文档检索" tabindex="-1">14. 完整案例：多租户文档检索 <a class="header-anchor" href="#_14-完整案例-多租户文档检索" aria-label="Permalink to &quot;14. 完整案例：多租户文档检索&quot;">​</a></h2><h3 id="输入与约束-1" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束-1" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>文档含敏感ACL，搜索支持全文和聚合，任何泄露不可接受。</p><h3 id="处理步骤-1" tabindex="-1">处理步骤 <a class="header-anchor" href="#处理步骤-1" aria-label="Permalink to &quot;处理步骤&quot;">​</a></h3><ol><li>索引文档携带tenant与可查询ACL模型。</li><li>认证主体转换为受控filter，不接受客户端tenant。</li><li>filter同时约束hits、highlight和aggregation。</li><li>高敏字段不进入索引或单独权限域。</li><li>数据库最终授权敏感下载，搜索只返回候选ID。</li></ol><h3 id="输出-1" tabindex="-1">输出 <a class="header-anchor" href="#输出-1" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>搜索结果与计数均不跨租户，下载再次授权。</p><h3 id="验证-1" tabindex="-1">验证 <a class="header-anchor" href="#验证-1" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>无权文档ID/词/聚合均不可推断；缓存key含权限版本。</p><h3 id="失败分支-1" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支-1" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>只过滤hits会通过total/facet泄露存在性；权限必须在搜索执行层覆盖全部输出。</p><h3 id="完成判断-1" tabindex="-1">完成判断 <a class="header-anchor" href="#完成判断-1" aria-label="Permalink to &quot;完成判断&quot;">​</a></h3><p>多租户检索以“不可推断”为门槛：无权文档不能出现在 hit、total、facet、highlight 或缓存侧信道中，下载时数据库再次授权，权限版本改变后相关缓存立即失效。</p><h2 id="_15-失败注入矩阵" tabindex="-1">15. 失败注入矩阵 <a class="header-anchor" href="#_15-失败注入矩阵" aria-label="Permalink to &quot;15. 失败注入矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>注入点</th><th>应观察的系统行为</th><th>不允许的结果</th></tr></thead><tbody><tr><td>输入中加入未知字段/极端长度</td><td>cluster_health 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>暂停一个处理节点</td><td>unassigned_shards 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>让下游返回429或503</td><td>search_partial 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>制造重复与乱序版本</td><td>search_p99 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>使磁盘达到高水位</td><td>indexing_rejections 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>让请求在提交后断线</td><td>freshness_lag 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>撤销一个租户权限</td><td>shard_size 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>使后台任务积压超过SLO</td><td>heap_pressure 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr></tbody></table><h2 id="_16-调试路径与观测信号" tabindex="-1">16. 调试路径与观测信号 <a class="header-anchor" href="#_16-调试路径与观测信号" aria-label="Permalink to &quot;16. 调试路径与观测信号&quot;">​</a></h2><ol><li><code>cluster_health</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>unassigned_shards</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>search_partial</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>search_p99</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>indexing_rejections</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>freshness_lag</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>shard_size</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>heap_pressure</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>snapshot_restore_test</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>authorization_leak_tests</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li></ol><p>出现 partial result 时先查 cluster health、失败 shard 与副本分配，再判断是否允许返回；freshness 问题用事实源版本减索引版本定位 backlog。授权问题单独跑跨租户 golden tests，不能从总体 search p99 推断安全正确。</p><h2 id="_17-性能、安全与运维边界" tabindex="-1">17. 性能、安全与运维边界 <a class="header-anchor" href="#_17-性能、安全与运维边界" aria-label="Permalink to &quot;17. 性能、安全与运维边界&quot;">​</a></h2><ol><li>所有用户输入有长度、结构、复杂度和超时上限；对 搜索引擎作为派生系统：权威边界、可靠性与容量 的实现要给出责任人和可执行验证。</li><li>租户与权限条件来自认证主体，不信任请求正文；对 搜索引擎作为派生系统：权威边界、可靠性与容量 的实现要给出责任人和可执行验证。</li><li>重试有总预算、退避、抖动和幂等保护；对 搜索引擎作为派生系统：权威边界、可靠性与容量 的实现要给出责任人和可执行验证。</li><li>派生数据能从事实源按明确水位重建；对 搜索引擎作为派生系统：权威边界、可靠性与容量 的实现要给出责任人和可执行验证。</li><li>敏感正文不进入普通日志、指标标签或公开快照；对 搜索引擎作为派生系统：权威边界、可靠性与容量 的实现要给出责任人和可执行验证。</li><li>容量按峰值写入、查询、恢复和副本同时估算；对 搜索引擎作为派生系统：权威边界、可靠性与容量 的实现要给出责任人和可执行验证。</li><li>发布采用版本化结构、canary、对账和回退窗口；对 搜索引擎作为派生系统：权威边界、可靠性与容量 的实现要给出责任人和可执行验证。</li><li>删除覆盖索引、缓存、快照与下游派生系统；对 搜索引擎作为派生系统：权威边界、可靠性与容量 的实现要给出责任人和可执行验证。</li><li>依赖不可用时核心正确性不由降级路径破坏；对 搜索引擎作为派生系统：权威边界、可靠性与容量 的实现要给出责任人和可执行验证。</li><li>运行手册包含暂停、恢复、验证和人工升级条件；对 搜索引擎作为派生系统：权威边界、可靠性与容量 的实现要给出责任人和可执行验证。</li></ol><h2 id="_18-综合练习与验收" tabindex="-1">18. 综合练习与验收 <a class="header-anchor" href="#_18-综合练习与验收" aria-label="Permalink to &quot;18. 综合练习与验收&quot;">​</a></h2><p>为“电商搜索降级”实现最小生产链路，并把“多租户文档检索”作为不同约束下的对照。提交配置、请求/响应、数据样例、故障脚本和观测面板。</p><ul><li>[ ] 验收 1：事实来源 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 2：派生投影 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 3：Near real time 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 4：Partial results 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 5：Quorum与副本 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 6：Snapshot 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 7：权限过滤 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 8：容量分片 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 搜索不可用、部分 shard 失败和 freshness 超限分别映射到明确产品状态，不静默返回不完整结果。</li><li>[ ] 多租户测试覆盖 hits、total、facet、highlight、cache key 和最终下载授权。</li><li>[ ] 容量计划同时包含正常查询、在线写入、节点故障副本恢复与全量重建的磁盘和吞吐余量。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://docs.opensearch.org/latest/api-reference/cluster-api/cluster-health/" target="_blank" rel="noreferrer">OpenSearch Cluster health</a>（访问日期：2026-07-17）</li><li><a href="https://docs.opensearch.org/latest/tuning-your-cluster/availability-and-recovery/snapshots/" target="_blank" rel="noreferrer">OpenSearch Snapshot and restore</a>（访问日期：2026-07-17）</li><li><a href="https://docs.opensearch.org/latest/api-reference/search-apis/search/" target="_blank" rel="noreferrer">OpenSearch Search API</a>（访问日期：2026-07-17）</li><li><a href="https://www.elastic.co/docs/deploy-manage/production-guidance/availability-and-resilience/resilience-in-larger-clusters" target="_blank" rel="noreferrer">Elasticsearch Resilience in larger clusters</a>（访问日期：2026-07-17）</li><li><a href="https://docs.opensearch.org/latest/version-history/" target="_blank" rel="noreferrer">OpenSearch 3.7 version history</a>（访问日期：2026-07-17）</li></ul>`,115)])])}const b=e(l,[["render",s]]);export{u as __pageData,b as default};
